import type {ContentSourceMap, ContentSourceMapMapping, ContentSourceMapParsedPath} from './types'

/**
 * @internal
 */
export function resolveMapping(
  resultPath: ContentSourceMapParsedPath,
  csm?: ContentSourceMap,
):
  | {
      mapping: ContentSourceMapMapping
      matchedPath: string
      pathSuffix: string
    }
  | undefined {
  if (!csm?.mappings) {
    return undefined
  }
  const resultMappingPath = jsonPath(jsonPathToMappingPath(resultPath))

  if (csm.mappings[resultMappingPath] !== undefined) {
    return {
      mapping: csm.mappings[resultMappingPath],
      matchedPath: resultMappingPath,
      pathSuffix: '',
    }
  }

  const resultMappingPathArray = jsonPathArray(jsonPathToMappingPath(resultPath))
  for (let i = resultMappingPathArray.length - 1; i >= 0; i--) {
    const key = `$${resultMappingPathArray.slice(0, i).join('')}`
    const mappingFound = csm.mappings[key]
    if (mappingFound) {
      const pathSuffix = resultMappingPath.substring(key.length)
      return {mapping: mappingFound, matchedPath: key, pathSuffix}
    }
  }

  return undefined
}
/** @internal */
export function isArray(value: unknown): value is Array<unknown> {
  return value !== null && Array.isArray(value)
}
import {isRecord} from '../util/isRecord'
import {isArray} from './isArray'
import type {ContentSourceMapParsedPath, WalkMapFn} from './types'

/**
 * generic way to walk a nested object or array and apply a mapping function to each value
 * @internal
 */
export function walkMap(
  value: unknown,
  mappingFn: WalkMapFn,
  path: ContentSourceMapParsedPath = [],
): unknown {
  if (isArray(value)) {
    return value.map((v, idx) => {
      if (isRecord(v)) {
        const _key = v['_key']
        if (typeof _key === 'string') {
          return walkMap(v, mappingFn, path.concat({_key, _index: idx}))
        }
      }

      return walkMap(v, mappingFn, path.concat(idx))
    })
  }

  if (isRecord(value)) {
    // Handle Portable Text in a faster way
    if (value._type === 'block' || value._type === 'span') {
      const result = {...value}
      if (value._type === 'block') {
        result.children = walkMap(value.children, mappingFn, path.concat('children'))
      } else if (value._type === 'span') {
        result.text = walkMap(value.text, mappingFn, path.concat('text'))
      }
      return result
    }

    return Object.fromEntries(
      Object.entries(value).map(([k, v]) => [k, walkMap(v, mappingFn, path.concat(k))]),
    )
  }

  return mappingFn(value, path)
}
import {getPublishedId, getVersionFromId, isPublishedId, isVersionId} from './draftUtils'
import {jsonPathToStudioPath} from './jsonPath'
import * as studioPath from './studioPath'
import type {CreateEditUrlOptions, EditIntentUrl, StudioBaseUrl} from './types'

/** @internal */
export function createEditUrl(options: CreateEditUrlOptions): `${StudioBaseUrl}${EditIntentUrl}` {
  const {
    baseUrl,
    workspace: _workspace = 'default',
    tool: _tool = 'default',
    id: _id,
    type,
    path,
    projectId,
    dataset,
  } = options

  if (!baseUrl) {
    throw new Error('baseUrl is required')
  }
  if (!path) {
    throw new Error('path is required')
  }
  if (!_id) {
    throw new Error('id is required')
  }
  if (baseUrl !== '/' && baseUrl.endsWith('/')) {
    throw new Error('baseUrl must not end with a slash')
  }

  const workspace = _workspace === 'default' ? undefined : _workspace
  const tool = _tool === 'default' ? undefined : _tool
  const id = getPublishedId(_id)
  const stringifiedPath = Array.isArray(path)
    ? studioPath.toString(jsonPathToStudioPath(path))
    : path

  // eslint-disable-next-line no-warning-comments
  // @TODO Using searchParams as a temporary workaround until `@sanity/overlays` can decode state from the path reliably
  const searchParams = new URLSearchParams({
    baseUrl,
    id,
    type,
    path: stringifiedPath,
  })
  if (workspace) {
    searchParams.set('workspace', workspace)
  }
  if (tool) {
    searchParams.set('tool', tool)
  }
  if (projectId) {
    searchParams.set('projectId', projectId)
  }
  if (dataset) {
    searchParams.set('dataset', dataset)
  }
  if (isPublishedId(_id)) {
    searchParams.set('perspective', 'published')
  } else if (isVersionId(_id)) {
    const versionId = getVersionFromId(_id)!
    searchParams.set('perspective', versionId)
  }

  const segments = [baseUrl === '/' ? '' : baseUrl]
  if (workspace) {
    segments.push(workspace)
  }
  const routerParams = [
    'mode=presentation',
    `id=${id}`,
    `type=${type}`,
    `path=${encodeURIComponent(stringifiedPath)}`,
  ]
  if (tool) {
    routerParams.push(`tool=${tool}`)
  }
  segments.push('intent', 'edit', `${routerParams.join(';')}?${searchParams}`)
  return segments.join('/') as unknown as `${StudioBaseUrl}${EditIntentUrl}`
}
import {parseJsonPath} from './jsonPath'
import {resolveMapping} from './resolveMapping'
import type {
  CreateEditUrlOptions,
  ResolveEditInfoOptions,
  StudioBaseRoute,
  StudioBaseUrl,
  StudioUrl,
} from './types'

/** @internal */
export function resolveEditInfo(options: ResolveEditInfoOptions): CreateEditUrlOptions | undefined {
  const {resultSourceMap: csm, resultPath} = options
  const {mapping, pathSuffix} = resolveMapping(resultPath, csm) || {}

  if (!mapping) {
    // console.warn('no mapping for path', { path: resultPath, sourceMap: csm })
    return undefined
  }

  if (mapping.source.type === 'literal') {
    return undefined
  }

  if (mapping.source.type === 'unknown') {
    return undefined
  }

  const sourceDoc = csm.documents[mapping.source.document]
  const sourcePath = csm.paths[mapping.source.path]

  if (sourceDoc && sourcePath) {
    const {baseUrl, workspace, tool} = resolveStudioBaseRoute(
      typeof options.studioUrl === 'function' ? options.studioUrl(sourceDoc) : options.studioUrl,
    )
    if (!baseUrl) return undefined
    const {_id, _type, _projectId, _dataset} = sourceDoc
    return {
      baseUrl,
      workspace,
      tool,
      id: _id,
      type: _type,
      path: parseJsonPath(sourcePath + pathSuffix),
      projectId: _projectId,
      dataset: _dataset,
    } satisfies CreateEditUrlOptions
  }

  return undefined
}

/** @internal */
export function resolveStudioBaseRoute(studioUrl: StudioUrl): StudioBaseRoute {
  let baseUrl: StudioBaseUrl = typeof studioUrl === 'string' ? studioUrl : studioUrl.baseUrl
  if (baseUrl !== '/') {
    baseUrl = baseUrl.replace(/\/$/, '')
  }
  if (typeof studioUrl === 'string') {
    return {baseUrl}
  }
  return {...studioUrl, baseUrl}
}
